<template>
  <section class="demo" aria-labelledby="product-demo-title">
    <header class="demo-head">
      <small>HTEX AI WORKFLOW</small>
      <h2 id="product-demo-title">{{ c.title }}</h2>
      <p>{{ c.subtitle }}</p>
    </header>

    <nav class="demo-tabs" :aria-label="c.tabsLabel">
      <button v-for="(tab, i) in c.tabs" :key="tab" type="button" :class="{ on: scene === i }" :aria-current="scene === i ? 'step' : undefined" tabindex="-1">
        <i>0{{ i + 1 }}</i>{{ tab }}
      </button>
    </nav>

    <div class="stage">
      <div class="window">
        <div class="window-bar"><i class="red"/><i class="yellow"/><i class="green"/><b>{{ windowTitle }}</b><span>•••</span></div>

        <!-- 1. itinerary -->
        <template v-if="scene === 0">
          <DemoNav :copy="c" />
          <div class="body">
            <div class="steps"><span>{{ c.identity }}</span><span>{{ c.work }}</span><span>{{ c.finance }}</span><span class="on">{{ c.trip }}</span><span>{{ c.form }}</span></div>
            <div class="setup">
              <label>{{ c.destination }}<strong>{{ example.destination }}</strong></label>
              <label>{{ c.days }}<select v-model="days"><option value="5">5 {{ c.dayUnit }}</option><option value="7">7 {{ c.dayUnit }}</option></select></label>
              <button :class="{ loading: tripPhase === 1 }" @click="generateTrip">{{ tripPhase === 2 ? c.regenerate : c.generate }}</button>
            </div>
            <Transition name="rise">
              <div v-if="tripPhase === 2" class="trip-result">
                <div class="table-card">
                  <table><thead><tr><th>{{ c.day }}</th><th>{{ c.date }}</th><th>{{ c.city }}</th><th>{{ c.transport }}</th><th>{{ c.plan }}</th><th>{{ c.hotel }}</th></tr></thead>
                    <tbody><tr v-for="row in itineraryRows" :key="row[0]"><td v-for="(cell, j) in row" :key="j"><em v-if="j > 2">{{ cell }}</em><template v-else>{{ cell }}</template></td></tr></tbody>
                  </table>
                </div>
                <aside class="thumb"><h3>{{ days }} {{ c.dayItinerary }}</h3><p>{{ example.route }}</p><div class="route-map"><div class="flight-leg flight-leg--ab"/><div class="flight-leg flight-leg--bc"/><span class="map-node map-node--start"><i/>{{ example.origin }}</span><span class="map-node map-node--middle"><i/>{{ example.middle }}</span><span class="map-node map-node--end"><i/>{{ example.end }}</span><b class="plane" aria-hidden="true">✈</b></div><footer><span>09/12</span><span>09/{{ days === '5' ? '16' : '18' }}</span></footer></aside>
              </div>
            </Transition>
          </div>
        </template>

        <!-- 2. diagnosis -->
        <template v-else-if="scene === 1">
          <DemoNav :copy="c" />
          <div class="body diagnosis">
            <h3>{{ c.diagnosisTitle }}</h3><p>{{ c.diagnosisSub }}</p>
            <div class="materials"><div v-for="m in c.materials" :key="m"><i>✓</i><b>{{ m }}</b><small>{{ c.local }}</small></div></div>
            <button class="check-btn" @click="runCheck">{{ checkProgress > 0 && checkProgress < 100 ? c.checking : c.startCheck }}</button>
            <div class="scorebox">
              <div class="gauge" :style="{ '--score': `${displayScore}%` }"><b>{{ checkDone ? 62 : checkProgress }}</b></div>
              <div class="score-meta"><strong>{{ checkDone ? c.mediumRisk : (checkProgress ? c.scoring : c.ready) }}</strong><div class="bar"><i :style="{ width: `${checkProgress}%` }"/></div><footer><span>{{ checkItem }}</span><b>{{ checkProgress }}%</b></footer></div>
            </div>
            <Transition name="rise"><div v-if="checkDone" class="issues"><article class="danger"><b>{{ c.issue1 }}</b><p>{{ c.fix1 }}</p></article><article class="warn"><b>{{ c.issue2 }}</b><p>{{ c.fix2 }}</p></article></div></Transition>
          </div>
        </template>

        <!-- 3. mother-tongue guidance on DS-160 -->
        <template v-else>
          <div class="us-head"><b>U.S. Department of State</b><span>Consular Electronic Application Center</span></div>
          <div class="us-sub">DS-160 · Personal Information 1　|　Application ID: AA00••••••</div>
          <div class="us-body">
            <main><h2>Personal Information 1</h2><p>Fields marked with * are required.</p>
              <label v-for="field in usFields" :key="field.key" :class="{ focus: tipKey === field.key }" @click="tipKey = field.key">{{ field.label }} *<input :value="field.value" readonly /></label>
            </main>
            <aside class="hint"><header><b>Htex · {{ c.nativeHelp }}</b></header><section><h3>{{ currentTip.title }}</h3><p>{{ currentTip.text }}</p><div class="example"><span>{{ c.nativeName }}：{{ example.native }}</span><b>{{ currentTip.example }}</b></div><nav><button v-for="key in tipKeys" :key="key" :class="{ on: tipKey === key }" tabindex="-1">{{ c.tipLabels[key] }}</button></nav><small>{{ c.confirmNotice }}</small></section></aside>
          </div>
        </template>
      </div>
      <div class="timeline"><i :key="timelineKey"/></div>
    </div>
    <p class="caption"><b>{{ c.tabs[scene] }}</b>{{ c.descriptions[scene] }}</p>
  </section>
</template>

<script setup>
import { computed, defineComponent, h, onBeforeUnmount, onMounted, ref, watch } from 'vue'
import { useI18n } from 'vue-i18n'

const { locale } = useI18n()
const scene = ref(0), timelineKey = ref(0), days = ref('5'), tripPhase = ref(0)
const checkProgress = ref(0), tipKey = ref('surname')
let sceneTimer, flowTimer, tipTimer

const DemoNav = defineComponent({ props:{ copy:Object }, setup(p){ return()=>h('div',{class:'app-nav'},[h('b','Htex'),h('span',p.copy.apply),h('span',p.copy.eligibility),h('span',p.copy.policies),h('i',p.copy.privacy)]) } })

const dict = {
  'zh-CN': {title:'一个界面，完成整套签证材料',subtitle:'从行程规划到材料校验，再到母语填写，智能助手在关键步骤提供辅助。',tabsLabel:'产品演示',tabs:['智能补充行程','智能材料校验','美签母语提示'],descriptions:['选好天数后自动生成每日行程与缩略图。','逐项校验、动态评分，并明确指出材料问题。','在 DS-160 字段旁使用中文解释填写规则。'],apply:'办签证',eligibility:'查通过率',policies:'看政策',privacy:'隐私保护',identity:'身份证明',work:'工作 / 在职',finance:'财务证明',trip:'行程 / 住宿',form:'签证表格',destination:'目的地',days:'出行天数',dayUnit:'天',generate:'自动生成行程单',regenerate:'重新生成',day:'天数',date:'日期',city:'城市',transport:'交通',plan:'行程 / 景点',hotel:'住宿',dayItinerary:'日行程单',diagnosisTitle:'智能材料校验',diagnosisSub:'护照、银行流水、在职证明与行程单已准备完成',materials:['护照资料页','近 3 个月银行流水','在职证明','行程单'],local:'本机',startCheck:'开始智能校验',checking:'校验中…',ready:'等待开始检查',scoring:'正在综合评分',mediumRisk:'评分完成 · 中等风险',checks:['检查护照有效期','核对收入与银行流水','比对行程预算和材料'],issue1:'银行流水第 3 页：余额与行程预算不匹配',fix1:'建议补充稳定收入记录，或将预算调整至合理范围。',issue2:'护照资料页：有效期距返程日不足 6 个月',fix2:'建议更新护照后再提交申请。',nativeHelp:'中文填写提示',nativeName:'你的中文姓名',confirmNotice:'仅提供填写辅助，最终内容由用户确认后提交。',tipLabels:{surname:'姓',given:'名',native:'中文姓名',marital:'婚姻'},tips:{surname:['姓（Surnames）怎么填？','填写护照机读区中的姓，使用大写英文字母。','此处填写：ZHANG'],given:['名（Given Names）怎么填？','填写护照上的全部名字，顺序须与护照一致。','此处填写：WEI'],native:['中文姓名怎么填？','使用中文填写完整姓名。','此处填写：张伟'],marital:['婚姻状态怎么选？','按照当前法律婚姻状态选择。','此处选择：SINGLE']}},
  en: {title:'One workspace for your visa application',subtitle:'Plan an itinerary, check documents, and complete official forms with intelligent assistance.',tabsLabel:'Product demos',tabs:['Build an itinerary','Smart document check','DS-160 language help'],descriptions:['Choose trip length and generate a complete itinerary preview.','Watch the smart check score the application and identify exact issues.','Understand DS-160 fields with guidance in your language.'],apply:'Apply',eligibility:'Check eligibility',policies:'Policies',privacy:'Privacy first',identity:'Identity',work:'Employment',finance:'Financial',trip:'Itinerary',form:'Application form',destination:'Destination',days:'Trip length',dayUnit:'days',generate:'Generate itinerary',regenerate:'Generate again',day:'Day',date:'Date',city:'City',transport:'Transport',plan:'Activities',hotel:'Hotel',dayItinerary:'day itinerary',diagnosisTitle:'Smart document check',diagnosisSub:'Passport, bank statement, employment letter, and itinerary are ready',materials:['Passport bio page','3-month bank statement','Employment letter','Itinerary'],local:'On device',startCheck:'Start smart check',checking:'Checking…',ready:'Ready to check',scoring:'Calculating the score',mediumRisk:'Complete · Medium risk',checks:['Checking passport validity','Matching income and statements','Comparing itinerary budget'],issue1:'Bank statement page 3: balance does not match trip budget',fix1:'Add stable income records or adjust the proposed budget.',issue2:'Passport bio page: less than 6 months validity after return',fix2:'Renew the passport before submission.',nativeHelp:'English guidance',nativeName:'Your full name',confirmNotice:'Guidance only. You review and confirm before submission.',tipLabels:{surname:'Surname',given:'Given',native:'Native',marital:'Status'},tips:{surname:['How to enter Surnames','Use the surname shown in the passport MRZ, in uppercase Latin letters.','Enter: SMITH'],given:['How to enter Given Names','Enter every given name in the same order as the passport.','Enter: EMILY ROSE'],native:['Name in native alphabet','Use your native script; select Does Not Apply if unavailable.','Enter: EMILY ROSE SMITH'],marital:['Marital status','Choose your current legal marital status.','Select: SINGLE']}},
  'vi-VN': {title:'Một giao diện cho toàn bộ hồ sơ visa',subtitle:'AI hỗ trợ từ lập lịch trình, kiểm tra tài liệu đến điền biểu mẫu bằng tiếng mẹ đẻ.',tabsLabel:'Bản trình diễn',tabs:['Tạo lịch trình thông minh','AI kiểm tra tài liệu','Gợi ý tiếng Việt cho DS-160'],descriptions:['Chọn số ngày và tự động tạo lịch trình cùng bản xem trước.','Theo dõi tiến độ chấm điểm và xem lỗi cụ thể.','Hiểu từng trường DS-160 bằng hướng dẫn tiếng Việt.'],apply:'Làm visa',eligibility:'Kiểm tra khả năng',policies:'Chính sách',privacy:'Ưu tiên riêng tư',identity:'Danh tính',work:'Công việc',finance:'Tài chính',trip:'Lịch trình',form:'Biểu mẫu',destination:'Điểm đến',days:'Số ngày',dayUnit:'ngày',generate:'Tự động tạo lịch trình',regenerate:'Tạo lại',day:'Ngày',date:'Ngày tháng',city:'Thành phố',transport:'Di chuyển',plan:'Hoạt động',hotel:'Khách sạn',dayItinerary:'ngày',diagnosisTitle:'AI kiểm tra tài liệu',diagnosisSub:'Hộ chiếu, sao kê, xác nhận công việc và lịch trình đã sẵn sàng',materials:['Trang thông tin hộ chiếu','Sao kê 3 tháng','Xác nhận công việc','Lịch trình'],local:'Trên máy',startCheck:'Bắt đầu kiểm tra AI',checking:'Đang kiểm tra…',ready:'Sẵn sàng kiểm tra',scoring:'AI đang tính điểm',mediumRisk:'Hoàn tất · Rủi ro trung bình',checks:['Kiểm tra hạn hộ chiếu','Đối chiếu thu nhập và sao kê','So sánh ngân sách chuyến đi'],issue1:'Sao kê trang 3: số dư không khớp ngân sách chuyến đi',fix1:'Bổ sung thu nhập ổn định hoặc điều chỉnh ngân sách.',issue2:'Hộ chiếu: thời hạn sau ngày về dưới 6 tháng',fix2:'Nên gia hạn hộ chiếu trước khi nộp.',nativeHelp:'Hướng dẫn tiếng Việt',nativeName:'Họ tên tiếng Việt',confirmNotice:'Chỉ hỗ trợ điền; bạn xác nhận trước khi nộp.',tipLabels:{surname:'Họ',given:'Tên',native:'Tiếng Việt',marital:'Hôn nhân'},tips:{surname:['Điền Surnames thế nào?','Nhập HỌ theo vùng MRZ của hộ chiếu, dùng chữ Latin in hoa.','Điền: NGUYEN'],given:['Điền Given Names thế nào?','Nhập toàn bộ tên theo đúng thứ tự trên hộ chiếu.','Điền: VAN AN'],native:['Tên bằng chữ mẹ đẻ','Nhập đầy đủ họ tên có dấu tiếng Việt.','Điền: Nguyễn Văn An'],marital:['Tình trạng hôn nhân','Chọn tình trạng hôn nhân pháp lý hiện tại.','Chọn: SINGLE']}},
  'id-ID': {title:'Satu tampilan untuk seluruh dokumen visa',subtitle:'AI membantu dari rencana perjalanan, pemeriksaan dokumen, hingga formulir bahasa ibu.',tabsLabel:'Demo produk',tabs:['Buat rencana perjalanan','Diagnosis dokumen AI','Panduan Bahasa untuk DS-160'],descriptions:['Pilih jumlah hari lalu buat itinerary dan pratinjau otomatis.','Lihat progres penilaian dan masalah dokumen secara tepat.','Pahami kolom DS-160 dengan panduan Bahasa Indonesia.'],apply:'Ajukan visa',eligibility:'Cek kelayakan',policies:'Kebijakan',privacy:'Privasi utama',identity:'Identitas',work:'Pekerjaan',finance:'Keuangan',trip:'Perjalanan',form:'Formulir',destination:'Tujuan',days:'Durasi',dayUnit:'hari',generate:'Buat itinerary otomatis',regenerate:'Buat ulang',day:'Hari',date:'Tanggal',city:'Kota',transport:'Transportasi',plan:'Kegiatan',hotel:'Hotel',dayItinerary:'hari',diagnosisTitle:'Pemeriksaan dokumen AI',diagnosisSub:'Paspor, rekening koran, surat kerja, dan itinerary sudah siap',materials:['Biodata paspor','Rekening koran 3 bulan','Surat keterangan kerja','Itinerary'],local:'Di perangkat',startCheck:'Mulai pemeriksaan AI',checking:'Memeriksa…',ready:'Siap diperiksa',scoring:'AI sedang menghitung skor',mediumRisk:'Selesai · Risiko sedang',checks:['Memeriksa masa berlaku paspor','Mencocokkan pendapatan dan rekening','Membandingkan anggaran perjalanan'],issue1:'Rekening halaman 3: saldo tidak sesuai anggaran perjalanan',fix1:'Tambahkan bukti pendapatan stabil atau sesuaikan anggaran.',issue2:'Paspor: masa berlaku setelah pulang kurang dari 6 bulan',fix2:'Perbarui paspor sebelum mengajukan.',nativeHelp:'Panduan Bahasa Indonesia',nativeName:'Nama lengkap Anda',confirmNotice:'Hanya panduan; Anda mengonfirmasi sebelum mengirim.',tipLabels:{surname:'Marga',given:'Nama',native:'Nama asli',marital:'Status'},tips:{surname:['Cara mengisi Surnames','Isi nama keluarga sesuai MRZ paspor dengan huruf Latin kapital.','Isi: SANTOSO'],given:['Cara mengisi Given Names','Isi semua nama depan sesuai urutan di paspor.','Isi: BUDI'],native:['Nama dalam alfabet asli','Isi nama lengkap sesuai dokumen lokal.','Isi: Budi Santoso'],marital:['Status perkawinan','Pilih status perkawinan resmi saat ini.','Pilih: SINGLE']}}
}

const c = computed(()=>dict[locale.value] || dict.en)
const example = computed(()=> locale.value==='vi-VN'?{native:'Nguyễn Văn An',surname:'NGUYEN',given:'VAN AN',destination:'Hoa Kỳ · Los Angeles / San Francisco',route:'Hà Nội → Los Angeles → San Francisco',origin:'Hà Nội',middle:'Los Angeles',end:'San Francisco'}:locale.value==='id-ID'?{native:'Budi Santoso',surname:'SANTOSO',given:'BUDI',destination:'Amerika Serikat · Los Angeles / San Francisco',route:'Jakarta → Los Angeles → San Francisco',origin:'Jakarta',middle:'Los Angeles',end:'San Francisco'}:locale.value==='zh-CN'?{native:'张伟',surname:'ZHANG',given:'WEI',destination:'美国 · 洛杉矶 / 旧金山',route:'北京 → 洛杉矶 → 旧金山',origin:'北京',middle:'洛杉矶',end:'旧金山'}:{native:'Emily Rose Smith',surname:'SMITH',given:'EMILY ROSE',destination:'United States · Los Angeles / San Francisco',route:'London → Los Angeles → San Francisco',origin:'London',middle:'Los Angeles',end:'San Francisco'})
const itineraryRows=computed(()=>[['Day 1','09/12','Los Angeles','Flight','Arrival · Hollywood','The Line LA'],['Day 2','09/13','Los Angeles','Walk','Griffith · Santa Monica','The Line LA'],['Day 3','09/14','San Francisco','Flight','Golden Gate Bridge','Hotel Zephyr'],['Day 4','09/15','San Francisco','Walk','Lombard Street','Hotel Zephyr'],['Day 5','09/16','San Francisco','Flight','Return','—']])
const displayScore=computed(()=>checkProgress.value===100?62:checkProgress.value),checkDone=computed(()=>checkProgress.value===100)
const checkItem=computed(()=>!checkProgress.value?c.value.ready:checkProgress.value<35?c.value.checks[0]:checkProgress.value<70?c.value.checks[1]:c.value.checks[2])
const tipKeys=['surname','given','native','marital']; const currentTip=computed(()=>{const t=c.value.tips[tipKey.value];return{title:t[0],text:t[1],example:t[2]}})
const usFields=computed(()=>[{key:'surname',label:'Surnames',value:example.value.surname},{key:'given',label:'Given Names',value:example.value.given},{key:'native',label:'Full Name in Native Alphabet',value:example.value.native},{key:'marital',label:'Marital Status',value:'SINGLE'}])
const windowTitle=computed(()=>scene.value===0?'Htex · Smart Itinerary':'Htex · Smart Document Check')

function generateTrip(){tripPhase.value=1;clearTimeout(flowTimer);flowTimer=setTimeout(()=>tripPhase.value=2,850)}
function runCheck(){checkProgress.value=0;clearInterval(flowTimer);flowTimer=setInterval(()=>{checkProgress.value=Math.min(100,checkProgress.value+4);if(checkProgress.value===100)clearInterval(flowTimer)},55)}
function startSceneFlow(){clearInterval(flowTimer);clearTimeout(flowTimer);clearInterval(tipTimer);if(scene.value===0){tripPhase.value=0;flowTimer=setTimeout(generateTrip,650)}else if(scene.value===1){checkProgress.value=0;flowTimer=setTimeout(runCheck,650)}else{tipKey.value='surname';let i=0;tipTimer=setInterval(()=>{i=(i+1)%tipKeys.length;tipKey.value=tipKeys[i]},1700)}}
function selectScene(i){scene.value=i;timelineKey.value++;startSceneFlow();schedule()}
function schedule(){clearInterval(sceneTimer);sceneTimer=setInterval(()=>selectScene((scene.value+1)%3),9000)}
watch(locale,()=>{timelineKey.value++;startSceneFlow()})
onMounted(()=>{startSceneFlow();schedule()});onBeforeUnmount(()=>{clearInterval(sceneTimer);clearInterval(flowTimer);clearTimeout(flowTimer);clearInterval(tipTimer)})
</script>

